export class DateRangePickerComponent implements OnChanges {
  /** Currently selected date range. */
  @Input() value: DateRange | null = null;
  /** Field label rendered above the control. */
  @Input() label = '';
  /** Placeholder shown when no range is selected. */
  @Input() placeholder = 'Select date range';
  /** Helper text shown below the control in the default state. */
  @Input() helperText = '';
  /** Error message shown when error=true. */
  @Input() errorMessage = '';
  /** Visual size of the picker. */
  @Input() size: DateRangePickerSize = 'md';
  /** Disables all interaction. */
  @Input() disabled = false;
  /** Shows error styling and errorMessage. */
  @Input() error = false;
  /** Earliest selectable date (inclusive). */
  @Input() minDate: Date | null = null;
  /** Latest selectable date (inclusive). */
  @Input() maxDate: Date | null = null;

  /** Emits the completed DateRange (or null when cleared). */
  @Output() valueChange = new EventEmitter<DateRange | null>();

  readonly weekdays = ['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'];

  isOpen = false;
  leftViewYear = new Date().getFullYear();
  leftViewMonth = new Date().getMonth();

  /** Pending start date — set on first click, waiting for the end click. */
  pendingStart: Date | null = null;
  /** Currently hovered date used for range preview during selection. */
  hoverDate: Date | null = null;

  constructor(private elementRef: ElementRef) {}

  // ─── Lifecycle ──────────────────────────────────────────────────────────────

  ngOnChanges(): void {
    if (this.value?.start) {
      this.leftViewYear = this.value.start.getFullYear();
      this.leftViewMonth = this.value.start.getMonth();
      // Ensure both months are not the same when value is set
      if (
        this.leftViewMonth === this.rightViewMonth &&
        this.leftViewYear === this.rightViewYear
      ) {
        // This won't happen as rightView is always leftView + 1 month
      }
    }
  }

  // ─── Outside-click close ────────────────────────────────────────────────────

  @HostListener('document:click', ['$event'])
  onDocumentClick(event: Event): void {
    if (!this.elementRef.nativeElement.contains(event.target)) {
      this.cancelPending();
      this.close();
    }
  }

  // ─── Open / close ───────────────────────────────────────────────────────────

  open(): void {
    if (this.disabled) return;
    if (this.value?.start) {
      this.leftViewYear = this.value.start.getFullYear();
      this.leftViewMonth = this.value.start.getMonth();
    }
    this.isOpen = true;
  }

  close(): void {
    this.isOpen = false;
  }

  onControlClick(): void {
    this.isOpen ? this.close() : this.open();
  }

  cancelPending(): void {
    this.pendingStart = null;
    this.hoverDate = null;
  }

  // ─── Navigation ─────────────────────────────────────────────────────────────

  prevMonth(): void {
    if (this.leftViewMonth === 0) {
      this.leftViewMonth = 11;
      this.leftViewYear--;
    } else {
      this.leftViewMonth--;
    }
  }

  nextMonth(): void {
    if (this.leftViewMonth === 11) {
      this.leftViewMonth = 0;
      this.leftViewYear++;
    } else {
      this.leftViewMonth++;
    }
  }

  // ─── Right calendar derived month/year ──────────────────────────────────────

  get rightViewMonth(): number {
    return this.leftViewMonth === 11 ? 0 : this.leftViewMonth + 1;
  }

  get rightViewYear(): number {
    return this.leftViewMonth === 11 ? this.leftViewYear + 1 : this.leftViewYear;
  }

  // ─── Day selection ──────────────────────────────────────────────────────────

  selectDay(cell: CalendarCell): void {
    if (cell.isDisabled) return;
    const date = new Date(cell.date);
    date.setHours(0, 0, 0, 0);

    if (!this.pendingStart) {
      // First click — set start and wait for end
      this.pendingStart = date;
    } else {
      // Second click — commit the range
      let start = this.pendingStart;
      let end = date;
      if (start > end) {
        [start, end] = [end, start];
      }
      this.value = { start, end };
      this.pendingStart = null;
      this.hoverDate = null;
      this.valueChange.emit(this.value);
      this.close();
    }
  }

  onDayHover(cell: CalendarCell): void {
    if (this.pendingStart && !cell.isDisabled) {
      this.hoverDate = new Date(cell.date);
      this.hoverDate.setHours(0, 0, 0, 0);
    }
  }

  onDayLeave(): void {
    if (this.pendingStart) {
      this.hoverDate = null;
    }
  }

  clear(event: Event): void {
    event.stopPropagation();
    this.value = null;
    this.pendingStart = null;
    this.hoverDate = null;
    this.valueChange.emit(null);
  }

  // ─── Computed properties ────────────────────────────────────────────────────

  get hasValue(): boolean {
    return !!(this.value?.start && this.value?.end);
  }

  get hasDisplayValue(): boolean {
    return !!(this.value?.start || this.pendingStart);
  }

  get displayValue(): string {
    if (this.value?.start && this.value?.end) {
      return `${this.formatDate(this.value.start)} – ${this.formatDate(this.value.end)}`;
    }
    if (this.pendingStart) {
      return `${this.formatDate(this.pendingStart)} – ...`;
    }
    return this.placeholder;
  }

  get leftMonthYearLabel(): string {
    return new Date(this.leftViewYear, this.leftViewMonth, 1).toLocaleDateString('en-US', {
      month: 'long',
      year: 'numeric',
    });
  }

  get rightMonthYearLabel(): string {
    return new Date(this.rightViewYear, this.rightViewMonth, 1).toLocaleDateString('en-US', {
      month: 'long',
      year: 'numeric',
    });
  }

  get leftCalendarCells(): CalendarCell[] {
    return this.buildCalendarCells(this.leftViewYear, this.leftViewMonth);
  }

  get rightCalendarCells(): CalendarCell[] {
    return this.buildCalendarCells(this.rightViewYear, this.rightViewMonth);
  }

  private buildCalendarCells(year: number, month: number): CalendarCell[] {
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const firstOfMonth = new Date(year, month, 1);
    const startOffset = firstOfMonth.getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const prevMonthDays = new Date(year, month, 0).getDate();

    const cells: CalendarCell[] = [];

    for (let i = startOffset - 1; i >= 0; i--) {
      const date = new Date(year, month - 1, prevMonthDays - i);
      cells.push(this.buildCell(date, false, today));
    }

    for (let d = 1; d <= daysInMonth; d++) {
      const date = new Date(year, month, d);
      cells.push(this.buildCell(date, true, today));
    }

    const remaining = 42 - cells.length;
    for (let d = 1; d <= remaining; d++) {
      const date = new Date(year, month + 1, d);
      cells.push(this.buildCell(date, false, today));
    }

    return cells;
  }

  private buildCell(date: Date, inMonth: boolean, today: Date): CalendarCell {
    const d = new Date(date);
    d.setHours(0, 0, 0, 0);

    const isToday = d.getTime() === today.getTime();

    let isDisabled = false;
    if (this.minDate) {
      const min = new Date(this.minDate);
      min.setHours(0, 0, 0, 0);
      if (d < min) isDisabled = true;
    }
    if (this.maxDate) {
      const max = new Date(this.maxDate);
      max.setHours(0, 0, 0, 0);
      if (d > max) isDisabled = true;
    }

    // Determine range boundaries — either committed value or pending preview
    let rangeStart: Date | null = null;
    let rangeEnd: Date | null = null;

    if (this.pendingStart) {
      const anchor = this.pendingStart;
      const hover = this.hoverDate ?? anchor;
      rangeStart = anchor <= hover ? anchor : hover;
      rangeEnd = anchor <= hover ? hover : anchor;
    } else if (this.value?.start && this.value?.end) {
      rangeStart = new Date(this.value.start);
      rangeStart.setHours(0, 0, 0, 0);
      rangeEnd = new Date(this.value.end);
      rangeEnd.setHours(0, 0, 0, 0);
    }

    const isRangeStart = rangeStart !== null && d.getTime() === rangeStart.getTime();
    const isRangeEnd = rangeEnd !== null && d.getTime() === rangeEnd.getTime();
    const isInRange =
      rangeStart !== null &&
      rangeEnd !== null &&
      d > rangeStart &&
      d < rangeEnd;

    return { date, inMonth, isToday, isDisabled, isRangeStart, isRangeEnd, isInRange };
  }

  formatDate(date: Date): string {
    return date.toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
    });
  }
}

interface CalendarCell {
  date: Date;
  inMonth: boolean;
  isToday: boolean;
  isDisabled: boolean;
  isRangeStart: boolean;
  isRangeEnd: boolean;
  isInRange: boolean;
}

import { Component, Input, Output, EventEmitter } from '@angular/core';
import { CommonModule } from '@angular/common';
import { CheckboxComponent, CheckboxSize } from './checkbox.component';

export interface CheckboxItem {
  id: string;
  label: string;
  checked: boolean;
  description?: string;
  disabled?: boolean;
}

@Component({
  selector: 'AppCore-checkbox-group',
  standalone: true,
  imports: [CommonModule, CheckboxComponent],
  styleUrls: ['./checkbox.scss'],
  template: `
    <div
      class="AppCore-checkbox-group"
      role="group"
      [attr.aria-labelledby]="groupLabel ? _labelId : null"
    >
      <!-- Group header -->
      <div *ngIf="groupLabel || groupDescription" class="AppCore-checkbox-group__header">
        <span
          *ngIf="groupLabel"
          class="AppCore-checkbox-group__label"
          [id]="_labelId"
        >{{ groupLabel }}</span>
        <span *ngIf="groupDescription" class="AppCore-checkbox-group__description">
          {{ groupDescription }}
        </span>
      </div>

      <!-- Select All row -->
      <ng-container *ngIf="showSelectAll">
        <AppCore-checkbox
          [label]="selectAllLabel"
          [checked]="allChecked"
          [indeterminate]="someChecked && !allChecked"
          [disabled]="disabled"
          [size]="size"
          (checkedChange)="onSelectAll($event)"
        ></AppCore-checkbox>
        <div class="AppCore-checkbox-group__divider"></div>
      </ng-container>

      <!-- Items -->
      <div
        class="AppCore-checkbox-group__items"
        [ngClass]="{ 'AppCore-checkbox-group__items--horizontal': orientation === 'horizontal' }"
      >
        <AppCore-checkbox
          *ngFor="let item of items; trackBy: trackById"
          [label]="item.label"
          [description]="item.description || ''"
          [checked]="item.checked"
          [disabled]="disabled || !!item.disabled"
          [error]="!!error"
          [size]="size"
          [inputId]="item.id"
          (checkedChange)="onItemChange(item, $event)"
        ></AppCore-checkbox>
      </div>

      <!-- Error message -->
      <span *ngIf="error" class="AppCore-checkbox-group__error" role="alert">
        {{ error }}
      </span>
    </div>
  `,
})
export class CheckboxGroupComponent {
  /** Array of checkbox items to render. */
  @Input() items: CheckboxItem[] = [];
  /** Group label displayed above the checkboxes. */
  @Input() groupLabel = '';
  /** Optional helper text below the group label. */
  @Input() groupDescription = '';
  /** Whether to show a "Select All" checkbox above the list. */
  @Input() showSelectAll = false;
  /** Label text for the select-all row. */
  @Input() selectAllLabel = 'Select All';
  /** Layout direction of the checkbox items. */
  @Input() orientation: 'vertical' | 'horizontal' = 'vertical';
  /** Size applied to all checkboxes in the group. */
  @Input() size: CheckboxSize = 'md';
  /** Disables all checkboxes in the group. */
  @Input() disabled = false;
  /** Error message displayed below the group; also applies error styling to each checkbox. */
  @Input() error = '';

  /** Emits the full updated items array on any selection change. */
  @Output() selectionChange = new EventEmitter<CheckboxItem[]>();

  readonly _labelId = `checkbox-group-label-${Math.random().toString(36).slice(2)}`;

  get allChecked(): boolean {
    return this.items.length > 0 && this.items.every(i => i.checked);
  }

  get someChecked(): boolean {
    return this.items.some(i => i.checked);
  }

  onSelectAll(checked: boolean): void {
    this.items = this.items.map(item =>
      item.disabled ? item : { ...item, checked }
    );
    this.selectionChange.emit([...this.items]);
  }

  onItemChange(item: CheckboxItem, checked: boolean): void {
    item.checked = checked;
    this.selectionChange.emit([...this.items]);
  }

  trackById(_index: number, item: CheckboxItem): string {
    return item.id;
  }
}

