  year: number;
  /** Zero-based month index (0 = January … 11 = December) */
  month: number;
}

interface MonthCell {
  /** Short month label shown in the grid (e.g. "Jan") */
  label: string;
  /** Zero-based month index */
  month: number;
  isSelected: boolean;
  isCurrentMonth: boolean;
