      color: inherit !important;
    }
  }

  // ===== Content =====
  &__content {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: $number-tokens-spacing-2;
  }

  &__title {
    font-size: $font-size-6;
    line-height: $line-height-6;
    font-weight: $font-weight-inter-1;
    color: inherit;
  }

  &__description {
    font-size: $font-size-7;
    line-height: $line-height-7;
    font-weight: $font-weight-inter-2;
    color: inherit;
  }

  // ===== Close button =====
  &__close {
    flex-shrink: 0;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: $number-tokens-padding-1;
    border: none;
    background: transparent;
    cursor: pointer;
    border-radius: $number-tokens-corner-radius-2;
    color: inherit;
    opacity: 0.7;
    transition: opacity 0.15s ease;

    &:hover {
      opacity: 1;
    }

    ::ng-deep .material-symbols-rounded {
      color: inherit !important;
    }
  }

  // ===== Information Type =====
