@use '../../styles/primitives' as *;

// Dot colors from Figma:
// inactive: #CEDDE8 (primary-blue-20)
// active:   #0C558C (primary-blue-60)

@keyframes AppCore-dot-pulse {
  0%, 100% {
    width: 8px;
    height: 8px;
    background-color: $primitives-colors-primary-blue-20;
  }
  50% {
    width: 12px;
    height: 12px;
    background-color: $primitives-colors-primary-blue-60-primary-color;
  }
}

.AppCore-dots-loader {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 16px;

  &__dot {
    display: block;
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background-color: $primitives-colors-primary-blue-20;
    animation: AppCore-dot-pulse 1.2s ease-in-out infinite;

    &--1 { animation-delay: 0s; }
    &--2 { animation-delay: 0.2s; }
    &--3 { animation-delay: 0.4s; }
    &--4 { animation-delay: 0.6s; }
  }
}

