@use '../../styles/primitives' as *;
@use '../../styles/numbers' as *;
@use '../../styles/typography' as *;
@use '../../styles/colors' as *;

.AppCore-modal {
  display: none;
  position: fixed;
  inset: 0;
  z-index: 1000;

  &--visible {
    display: block;
  }

  // ===== Overlay =====
  &__overlay {
    position: absolute;
    inset: 0;
    background-color: rgba(17, 17, 17, 0.6);
  }

  // ===== Modal panel =====
  &__panel {
    position: absolute;
    left: 50%;
    top: 50%;
    transform: translate(-50%, -50%);
    background-color: $color-tokens-surface-neutral-white;
    border-radius: $number-tokens-corner-radius-3;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    overflow: hidden;

    // Sizes from Figma: S=640×480, M=640×720, L=1200×560, XL=1400×720
    &--S  { width: 640px;  height: 480px; }
    &--M  { width: 640px;  height: 720px; }
    &--L  { width: 1200px; height: 560px; }
    &--XL { width: 1400px; height: 720px; }
  }

  // ===== Content (header + body) =====
  &__content {
    display: flex;
    flex-direction: column;
    align-items: stretch;
    gap: 4px;
    flex: 1;
    overflow: hidden;
  }

  // ===== Header =====
  &__header {
    display: flex;
    flex-direction: row;
    align-items: center;
    gap: 12px;
    padding: 12px 16px 8px;
    border-bottom: 1px solid $primitives-colors-neutral-gray-50;
    background-color: $color-tokens-surface-neutral-white;
    flex-shrink: 0;
  }

  &__title-group {
    display: flex;
    flex-direction: column;
    gap: 4px;
    flex: 1;
  }

  &__title {
    font-family: $font-inter;
    font-size: 20px;
    font-weight: $font-weight-inter-0; // 600 semi-bold
    line-height: 1.4em;
    color: $color-tokens-content-neutral-heading2-label2-body1;
  }

  &__subtitle {
    font-family: $font-inter;
    font-size: $font-size-6; // 14px
    font-weight: $font-weight-inter-2; // 400 regular
    line-height: 1.2857em;
    color: $color-tokens-content-neutral-body2;
  }

  // ===== Close button =====
  &__close {
    flex-shrink: 0;
    width: 32px;
    height: 32px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border: none;
    background: transparent;
    cursor: pointer;
    padding: 0;
    border-radius: $number-tokens-corner-radius-3;
    color: $color-tokens-content-neutral-body2;

    &:hover {
      background-color: $color-tokens-surface-neutral-white-hover;
    }

    ::ng-deep .material-symbols-rounded {
      font-size: 20px;
      color: $color-tokens-content-neutral-body2 !important;
    }
  }

  // ===== Body slot =====
  &__body {
    flex: 1;
    overflow-y: auto;
    padding: 12px 16px;
  }

  // ===== Footer CTAs =====
  &__footer {
    display: flex;
    flex-direction: row;
    justify-content: flex-end;
    align-items: center;
    padding: 16px 12px;
    border-top: 1px solid $primitives-colors-neutral-gray-50;
    background-color: $color-tokens-surface-neutral-white;
    flex-shrink: 0;
  }

  &__button-set {
    display: flex;
    flex-direction: row;
    gap: 12px;

    ::ng-deep .AppCore-button {
      width: 120px;
      min-width: 120px;
    }
  }
}

