  &--state-disabled {
    background-color: $color-tokens-surface-neutral-white;
    color: $color-tokens-content-neutral-disabled;
    font-weight: 400;
    cursor: not-allowed;
    pointer-events: none;
  }

  // State: Disabled Selected
  &--state-disabled-selected {
    background-color: $primitives-colors-neutral-gray-30;
    color: $color-tokens-content-neutral-disabled;
    font-weight: 500;
    cursor: not-allowed;
    pointer-events: none;
  }

  &__icon {
    width: 16px;
    height: 16px;
    display: flex;
    align-items: center;
    justify-content: center;

    ::ng-deep .icon,
    ::ng-deep .material-symbols-rounded {
      color: inherit !important;
      font-size: 16px !important;
      width: 16px !important;
      height: 16px !important;
    }
  }

  &__label {
    font-family: $font-inter;
    font-weight: inherit;
    color: inherit;
  }
}

