@use '../../styles/primitives' as *;
@use '../../styles/numbers' as *;
@use '../../styles/typography' as *;
@use '../../styles/colors' as *;

.AppCore-tree-view-item {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 4px;
  padding: 12px 8px;
  border-radius: $number-tokens-corner-radius-2;
  cursor: pointer;
  font-family: $font-inter;
  font-size: $font-size-label-sm;
  line-height: 18px;
  font-weight: $font-weight-inter-2;
  transition: background-color 0.15s ease;
  user-select: none;

  &--disabled {
    cursor: not-allowed;
    pointer-events: none;
  }

  // ── Level indentation ───────────────────────────────────────────────────────
  &--level-1 { padding-left: 8px; }
  &--level-2 { padding-left: 30px; }
  &--level-3 { padding-left: 52px; }
  &--level-4 { padding-left: 74px; }

  // ── Global type ─────────────────────────────────────────────────────────────
  &--type-global {
    background-color: $primitives-colors-primary-blue-10;
    color: $primitives-colors-neutral-gray-90;

    &.AppCore-tree-view-item--state-hover {
      background-color: $primitives-colors-primary-blue-20;
      color: $primitives-colors-neutral-gray-100;
    }

    &.AppCore-tree-view-item--state-pressed {
      background-color: $primitives-colors-primary-blue-10;
      color: $primitives-colors-neutral-gray-90;
    }

    &.AppCore-tree-view-item--state-selected {
      background-color: $primitives-colors-primary-blue-20;
      color: $primitives-colors-neutral-gray-90;
      font-weight: $font-weight-inter-0;
    }

    &.AppCore-tree-view-item--state-disabled {
      background-color: $primitives-colors-neutral-gray-30;
      color: $primitives-colors-neutral-gray-60;
    }
  }

  // ── Local type ──────────────────────────────────────────────────────────────
  &--type-local {
    background-color: $primitives-colors-neutral-white;
    color: $primitives-colors-neutral-gray-90;

    &.AppCore-tree-view-item--state-hover {
      background-color: $primitives-colors-neutral-gray-40;
      color: $primitives-colors-neutral-gray-100;
    }

    &.AppCore-tree-view-item--state-pressed {
      background-color: $primitives-colors-neutral-gray-30;
      color: $primitives-colors-neutral-gray-90;
    }

    &.AppCore-tree-view-item--state-selected {
      background-color: $primitives-colors-primary-blue-10;
      color: $primitives-colors-neutral-gray-90;
      font-weight: $font-weight-inter-0;
    }

    &.AppCore-tree-view-item--state-disabled {
      background-color: $primitives-colors-neutral-gray-30;
      color: $primitives-colors-neutral-gray-60;
    }
  }
}

// ── Icons ────────────────────────────────────────────────────────────────────
.AppCore-tree-view-item__prefix-icon {
  flex-shrink: 0;
  width: 18px;
  height: 18px;
  display: flex;
  align-items: center;
  justify-content: center;

  .material-symbols-rounded {
    font-size: 18px !important;
    width: 18px !important;
    height: 18px !important;
  }
}

.AppCore-tree-view-item__label {
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.AppCore-tree-view-item__chevron {
  flex-shrink: 0;
  margin-left: auto;
  width: 18px;
  height: 18px;
  display: flex;
  align-items: center;
  justify-content: center;

  .material-symbols-rounded {
    font-size: 18px !important;
    width: 18px !important;
    height: 18px !important;
  }
}

